# ===== src/checkout/checkout.py =====
from payments.payments import Payments
from inventory.inventory import Inventory


class Checkout:
    def __init__(self, payments, inventory):
        self.payments = payments
        self.inventory = inventory

    def submit_order(self, cart):
        hold = self.inventory.reserve_stock(cart.lines)
        charge = self.payments.capture_payment(cart.total, cart.token)
        if not charge.ok:
            self.inventory.release_stock(hold)
            raise PaymentDeclined(cart.id)
        return OrderReceipt(charge.id, hold.at)

# ===== src/payments/gateway.py =====
from lib.retry import with_retry


class PaymentGateway:
    def __init__(self, base_url, key):
        self.base_url = base_url
        self.key = key

    def send_charge(self, charge):
        res = http_post(self.base_url + "/charges", charge, self.key)
        if res.status >= 400:
            res = with_retry(self.base_url + "/charges", charge, self.key)
        return res.json()

# ===== src/inventory/inventory.py =====
from lib.db import db


class Inventory:
    def reserve_stock(self, lines):
        ids = [line.sku for line in lines]
        db.stock.decrement(ids)
        at = db.holds.insert(ids=ids, status="held")
        return StockHold(at.id, at.created)

    def release_stock(self, hold):
        db.holds.update(hold.id, status="released")
        db.stock.increment(hold.ids)

# ===== src/billing/subscriptions.py =====
from payments.gateway import PaymentGateway
from lib.db import db


class Subscriptions:
    def __init__(self, gateway):
        self.gateway = gateway

    def charge_cycle(self, sub):
        due = sub.plan.price_cents * sub.seats
        discount = round(due * sub.coupon.rate) if sub.coupon else 0
        self.gateway.send_charge(amount=due - discount, token=sub.token, idem=sub.cycle_id)
        db.subscriptions.update(sub.id, next_billing_at=now_ms() + sub.plan.interval_ms)

    def cancel(self, sub, reason):
        sub.status = "cancelled"
        sub.cancel_reason = reason
        db.subscriptions.update(sub.id, sub)

    def proration(self, sub, new_seats):
        remaining = sub.next_billing_at - now_ms()
        per_seat = sub.plan.price_cents * (remaining / sub.plan.interval_ms)
        return round(per_seat * (new_seats - sub.seats))

# ===== src/billing/payouts.py =====
from payments.gateway import PaymentGateway
from lib.db import db


class Payouts:
    def __init__(self, gateway):
        self.gateway = gateway

    def disburse_funds(self, account):
        net = account.balance_cents - account.fee_cents
        if net <= 0:
            raise NothingToDisburse(account.id)
        self.gateway.send_charge(amount=-net, ref=account.id, idem=account.payout_id)
        db.payouts.insert(account_id=account.id, net=net)

    def schedule(self, account, when):
        existing = db.payouts.pending(account.id)
        if existing:
            db.payouts.update(existing.id, scheduled_at=when)
        else:
            db.payouts.insert(account_id=account.id, scheduled_at=when)

    def statement(self, account, month):
        rows = db.payouts.for_month(account.id, month)
        total = sum(r.net for r in rows)
        return Statement(account.id, month, total, len(rows))

# ===== src/notify/notifier.py =====
from lib.db import db


class Notifier:
    def deliver_email(self, job):
        tpl = db.templates.get(job.template)
        html = render(tpl, job.vars)
        send_smtp(job.to, tpl.subject, html)
        db.outbox.insert(to=job.to, template=job.template)

    def deliver_sms(self, job):
        body = truncate(render(job.template, job.vars), 160)
        send_sms(job.phone, body)
        db.outbox.insert(to=job.phone, channel="sms")

    def retry_failed(self, since):
        failed = db.outbox.failed_since(since)
        for row in failed:
            self.deliver_email(row.job)
        return len(failed)

# ===== src/obs/metrics.py =====
class Metrics:
    def __init__(self):
        self.buf = []

    def record_event(self, name, value, tags):
        self.buf.append(Sample(name, value, tags, now_ms()))
        if len(self.buf) >= 500:
            self.flush()

    def gauge(self, name, value, tags):
        existing = next((i for i, s in enumerate(self.buf) if s.name == name), -1)
        if existing >= 0:
            self.buf[existing] = Sample(name, value, tags, now_ms())
        else:
            self.buf.append(Sample(name, value, tags, now_ms()))

    def flush(self):
        batch = self.buf[:]
        self.buf.clear()
        ship(batch)

# ===== src/config/loader.py =====
from schema import config_schema


class ConfigLoader:
    def load_settings(self, env):
        parsed = config_schema.validate(
            gateway_url=env.get("GATEWAY_URL"),
            retry_max=env.get("RETRY_MAX"),
            cache_ttl_ms=env.get("CACHE_TTL_MS"),
        )
        if not parsed.ok:
            raise BadConfig(parsed.error)
        return parsed.data

    def redact_for_log(self, cfg):
        return {"gateway_url": cfg.gateway_url, "retry_max": cfg.retry_max}

# ===== src/audit/audit.py =====
from lib.db import db


class AuditTrail:
    def append_entry(self, actor, action, meta):
        prev = db.audit.latest()
        digest = chain(prev.hash if prev else None, actor, action)
        db.audit.insert(actor=actor, action=action, meta=meta, hash=digest)

    def verify_chain(self):
        rows = db.audit.all()
        prev = None
        for row in rows:
            if chain(prev, row.actor, row.action) != row.hash:
                return False
            prev = row.hash
        return True

# ===== src/cache/session.py =====
class SessionCache:
    def __init__(self, ttl_ms):
        self.store = {}
        self.ttl_ms = ttl_ms

    def lookup_session(self, token):
        hit = self.store.get(token)
        if not hit or hit.exp < now_ms():
            self.store.pop(token, None)
            return None
        return hit.value

    def put_session(self, token, session):
        self.store[token] = Entry(session, now_ms() + self.ttl_ms)

    def evict_expired(self):
        now = now_ms()
        expired = [k for k, e in self.store.items() if e.exp < now]
        for k in expired:
            self.store.pop(k, None)
        return len(expired)
